example_bad:
fn main() {
    let ptr: *const i32 = &42;
    let val = *ptr; // Error: dereference of raw pointer requires unsafe

    libc::exit(0); // Error: call to unsafe function requires unsafe
}

fixes.code:
fn safe_deref(ptr: *const i32) -> Option<i32> {
    if ptr.is_null() {
        None
    } else {
        Some(unsafe { *ptr })
    }
}
